mapper.select:
SELECT id, run_id, step_id, artifact_type, s3_bucket, s3_key, public_url, mime_type,
       width, height, size_bytes, sha256, captured_at, created_at
FROM artifact
WHERE source_type = 'RUN'
  AND run_id = #{runId}
  AND id = #{id}

mapper.insert:
INSERT INTO artifact (
    id, run_id, step_id, artifact_type, s3_bucket, s3_key, public_url, mime_type,
    width, height, size_bytes, sha256, captured_at
)
VALUES (
    #{id}, #{runId}, #{stepId}, #{artifactType}, #{s3Bucket}, #{s3Key}, #{publicUrl}, #{mimeType},
    #{width}, #{height}, #{sizeBytes}, #{sha256}, #{capturedAt}
)
ON CONFLICT (id) DO NOTHING
